UPDATE USER_CREDENTIAL
SET LOGIN_ID   = #{loginId},
    UPDATED_AT = NOW(),
    UPDATED_BY = #{userId}
WHERE USER_ID  = #{userId}

UPDATE USER_CREDENTIAL
SET PASSWORD = #{password},
    PASSWORD_SET_YN = 'Y',
    UPDATED_AT = NOW(),
    UPDATED_BY = #{userId}
WHERE USER_ID = #{userId}

UPDATE USERS
SET NAME = #{name},
    UPDATED_AT = NOW(),
    UPDATED_BY = #{userId}
WHERE USER_ID = #{userId}

UPDATE USERS
SET NICKNAME = #{nickname},
    UPDATED_AT = NOW(),
    UPDATED_BY = #{userId}
WHERE USER_ID = #{userId}

UPDATE USERS
SET EMAIL = #{email},
    UPDATED_AT = NOW(),
    UPDATED_BY = #{userId}
WHERE USER_ID = #{userId}

UPDATE USERS
SET ADDR1 = #{addr1},
    ADDR2 = #{addr2},
    UPDATED_AT = NOW(),
    UPDATED_BY = #{userId}
WHERE USER_ID = #{userId}
